import React from 'react';

const ORBIT_LOGOS = [
  { top:-24, left:86, src:"", alt:"Cassiopea" },
  { top:31, left:181, src:"", alt:"Smarty" },
  { top:141, left:181, src:"", alt:"Teseo" },
  { top:196, left:86, src:"", alt:"InfoBusiness" },
  { top:141, left:-9, src:"", alt:"Follia" },
  { top:31, left:-9, src:"", alt:"Sostenibile" }
];

const ZCS_LOGO = "";

const styles = `
  @keyframes spinRing {
    from { transform: rotate(0deg); }
    to   { transform: rotate(360deg); }
  }
  @keyframes counterSpin {
    from { transform: rotate(0deg); }
    to   { transform: rotate(-360deg); }
  }
  @keyframes breathe {
    0%,100% { transform: translate(-50%,-50%) scale(1); }
    50%      { transform: translate(-50%,-50%) scale(1.05); }
  }
  @keyframes barSlide {
    0%   { width:0%;  margin-left:0%; }
    50%  { width:60%; margin-left:20%; }
    100% { width:0%;  margin-left:100%; }
  }
  @keyframes loadingFadeIn {
    from { opacity:0; }
    to   { opacity:1; }
  }
  @keyframes textPulse {
    0%,100% { opacity:0.3; }
    50%      { opacity:0.65; }
  }
`;

export function LoadingOverlay() {
  return (
    <>
      <style>{styles}</style>
      <div style={{
        position: 'fixed', inset: 0, zIndex: 9999,
        background: '#ffffff',
        display: 'flex', flexDirection: 'column',
        alignItems: 'center', justifyContent: 'center',
        gap: 36,
        animation: 'loadingFadeIn 0.3s ease-out',
      }}>
        {/* Orbit system */}
        <div style={{ position: 'relative', width: 220, height: 220 }}>
          
          {/* Logo ZCS centrale */}
          <img
            src={`data:image/png;base64,${ZCS_LOGO}`}
            alt="ZCS"
            style={{
              position: 'absolute', top: '50%', left: '50%',
              width: 110, height: 'auto',
              animation: 'breathe 4s ease-in-out infinite',
            }}
          />

          {/* Anello rotante */}
          <div style={{
            position: 'absolute', top: 0, left: 0,
            width: 220, height: 220,
            borderRadius: '50%',
            border: '1.5px dashed rgba(0,29,71,0.13)',
            animation: 'spinRing 16s linear infinite',
          }}>
            {ORBIT_LOGOS.map((logo, i) => (
              <div key={i} style={{
                position: 'absolute', top: logo.top, left: logo.left,
                width: 48, height: 48,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                background: '#fff',
                borderRadius: 12,
                boxShadow: '0 2px 12px rgba(0,29,71,0.11), 0 0 0 1px rgba(0,29,71,0.07)',
                padding: 7,
                animation: 'counterSpin 16s linear infinite',
              }}>
                <img
                  src={`data:image/png;base64,${logo.src}`}
                  alt={logo.alt}
                  style={{ width: '100%', height: '100%', objectFit: 'contain' }}
                />
              </div>
            ))}
          </div>
        </div>

        {/* Barra */}
        <div style={{ width: 180, height: 2, background: 'rgba(0,29,71,0.08)', borderRadius: 2, overflow: 'hidden' }}>
          <div style={{
            height: '100%',
            background: 'linear-gradient(90deg,#0d4d8a,#001d47)',
            borderRadius: 2,
            animation: 'barSlide 2s ease-in-out infinite',
          }}/>
        </div>

        {/* Testo */}
        <div style={{
          fontSize: 10, fontWeight: 600,
          letterSpacing: '0.35em', color: '#001d47',
          textTransform: 'uppercase',
          animation: 'textPulse 2s ease-in-out infinite',
        }}>
          Caricamento in corso
        </div>
      </div>
    </>
  );
}